      data->count = 0u;
      data->label.SetText("Count: 0");
      mCounter.SetAttachment(COUNTER_DATA_ID, Dali::Move(data))
        .SetBackgroundColor(UiColor(0x1565C0));
    }
  }

private:
  Application& mApplication;
  View         mCounter;
};

